module ring_counter(obf_clk, reset, q);

    input obf_clk;
    input reset;
    output [3:0] q;
    reg [3:0] q;
    initial q = 4'b0001;

    always @(posedge obf_clk)
        begin
            if (reset)
                q <= 4'b0001;
            else
                q <= {q[2:0], q[3]};
        end

endmodule
